      "Next": "RestoreResources"
    },
    "RestoreResources": {
      "Type": "Task",
      "Resource": "arn:aws:lambda:region:account:function:restoreResources",
      "Next": "UpdateEndpoints"
    },
    "UpdateEndpoints": {
      "Type": "Task",
